#include <bits/stdc++.h>
using namespace std;
long long l,r,prime[50004],sum=0;
bool np[1000006];
bool is_prime(int x){
    if(x<2)
        return 0;
    for(int i=2;i*i<=x;i++)
        if(x%i==0)
            return 0;
    return 1;
}
int main(){
    np[1]=1;
    scanf("%lld%lld",&l,&r);
    for(int i=2;i<=50000;i++)
        if(is_prime(i)) 
            prime[++sum]=i;
    for(int i=1;i<=sum;i++){
        long long tmp=l/prime[i]*prime[i]+(l%prime[i]>0)*prime[i];
        while(tmp<=r){
            if(tmp!=prime[i])
                np[tmp-l]=true;
            tmp+=prime[i];
        }
    }
    long long ans=0;
    for(int i=l;i<=r;i++)
        if(!np[i-l])
            ans++;
    printf("%lld",ans);
    return 0;
}
